/** @jsxImportSource @emotion/react */
import React, { useState } from 'react';
import { Breadcrumb, Tree } from '../..';

export default {
  title: 'Components/Breadcrumb/临时示例',
  component: Breadcrumb,
};

const routes = ['Home', 'Components', 'Breadcrumb', 'Breadcrumb.Item'];

export const MockRouter = () => {
  const [index, setIndex] = useState(routes.length - 1);
  return (
    <>
      <Breadcrumb maxCount={2}>
        {routes
          .filter((r, i) => i <= index)
          .map((r, i) => (
            <Breadcrumb.Item key={r} onClick={() => setIndex(i)}>
              {r}
            </Breadcrumb.Item>
          ))}
      </Breadcrumb>
      <Tree
        defaultExpandAll
        selectedKeys={[routes[index]]}
        onSelect={([key]) => {
          if (routes.indexOf(key) !== -1) {
            setIndex(routes.indexOf(key));
          }
        }}
        treeData={[
          {
            value: routes[0],
            children: [
              {
                value: routes[1],
                children: [
                  {
                    value: routes[2],
                    children: [
                      {
                        value: routes[3],
                      },
                    ],
                  },
                ],
              },
            ],
          },
        ]}
      />
    </>
  );
};
